const items = $input.all();
const now = new Date();
const timestamp = now.toISOString().replace(/[:.]/g, '-');

return items.map(item => {
  const schemaName = item.json.schema_name;
  const sqlContent = item.json.sql_content;
  const finalSql = `-- ============================================================\n-- FULL BACKUP — Schema: ${schemaName}\n-- Generated: ${now.toISOString()}\n-- ============================================================\n\n${sqlContent}`;
  return {
    json: {
      schema_name: schemaName,
      filename: `${schemaName}_full_${timestamp}.sql`,
      timestamp: now.toISOString(),
      content: finalSql,
      size_kb: (finalSql.length / 1024).toFixed(2)
    }
  };
});

const prepared = $('Prepare All Files').all();
const now = new Date();
const timestamp = now.toISOString().replace(/[:.]/g, '-');

const separator = `\n\n-- ============================================================\n-- ============================================================\n\n`;

const parts = prepared.map(item => item.json.content);
const consolidated = parts.join(separator);

const header = `-- ============================================================\n-- CONSOLIDATED FULL BACKUP — AGN (All Schemas)\n-- Generated: ${now.toISOString()}\n-- Schemas: ${prepared.map(i => i.json.schema_name).join(', ')}\n-- ============================================================\n\n`;

const finalContent = header + consolidated;

return [{
  json: {
    filename: `agn_consolidated_full_${timestamp}.sql`,
    timestamp: now.toISOString(),
    content: finalContent,
    size_kb: (finalContent.length / 1024).toFixed(2),
    schema_count: prepared.length
  }
}];

const prepared = $('Prepare All Files').all();
const consolidated = $('Prepare Consolidated File').first();

const rows = prepared.map(item => {
  const s = item.json.schema_name;
  const f = item.json.filename;
  const kb = item.json.size_kb;
  return `  ✔ ${String(s).padEnd(25)} ${kb} KB  →  schemas/${s}/${f}`;
}).join('\n');

const totalKb = prepared.reduce((acc, i) => acc + parseFloat(i.json.size_kb || 0), 0).toFixed(2);
const consolidatedKb = consolidated.json.size_kb;

const date = new Date().toLocaleDateString('es-AR', {
  year: 'numeric', month: 'long', day: 'numeric',
  hour: '2-digit', minute: '2-digit'
});

return [{
  json: {
    subject: `✅ Backup Supabase AGN — ${prepared.length} schemas procesados`,
    body: `REPORTE DE RESPALDO AUTOMATICO — AGN\n-----------------------------------------\nFecha:   ${date}\nEstado:  Exitoso\nSchemas: ${prepared.length}\n\nARCHIVOS INDIVIDUALES (schemas/):\n${rows}\n\nSUBTOTAL:  ${totalKb} KB\n\nARCHIVO CONSOLIDADO (consolidated/):\n  📦 ${consolidated.json.filename}   ${consolidatedKb} KB\n\n-----------------------------------------\nTodos los backups fueron subidos a GitHub.\nEste es un mensaje automatico del sistema.`
  }
}];

